+// Helper to capitalize slug segments as fallback
+function formatSlug(slug: string): string {
+  return slug
+    .split('-')
+    .map(word => word.charAt(0).toUpperCase() + word.slice(1))
+    .join(' ');
+}
+
+// Build custom crumbs array with page titles
+interface BreadcrumbItem {
+  text: string;
+  href: string;
+  class?: string;
+  onclick?: string;
+  tabindex?: string;
+}
+
+const crumbs: BreadcrumbItem[] = [];
+
+// Build breadcrumbs for each path segment
+for (let i = 0; i < segments.length; i++) {
+  const pathSegments = segments.slice(0, i + 1);
+  const href = '/' + pathSegments.join('/');
+  const slug = pathSegments.join('/');
+  const currentSegment = segments[i];
+
+  // Try to get the page title from content collection
+  let title: string | null = null;
+  let pageExists = false;
+
+  // Try index page first (e.g., guides/index.mdx for /guides)
+  const indexEntry = await getEntry('docs', `${slug}/index`);
+  if (indexEntry) {
+    title = indexEntry.data.title;
     pageExists = true;
+  } else {
+    // Try direct page (e.g., guides/quickstart.mdx for /guides/quickstart)
+    const directEntry = await getEntry('docs', slug);
+    if (directEntry) {
+      title = directEntry.data.title;
+      pageExists = true;
+    }
   }

+  // Use formatted slug as fallback if no page found
+  const text = title || formatSlug(currentSegment);
+
+  const crumb: BreadcrumbItem = {
+    text,
+    href: pageExists ? href : '#',
+  };
+
+  // Add disabled styling for non-existent pages
   if (!pageExists) {
-    // This intermediate path doesn't exist, so make it non-clickable
-    // Include c-breadcrumbs__link base class since the library replaces rather than merges classes
-    customizeLinks.push({
-      index: i + 1, // +1 because index 0 is Home
-      href: '#',
-      class: 'c-breadcrumbs__link breadcrumb-disabled',
-      onclick: 'return false;',
-      tabindex: '-1'
-    });
+    crumb.class = 'c-breadcrumbs__link breadcrumb-disabled';
+    crumb.onclick = 'return false;';
+    crumb.tabindex = '-1';
   }
+
+  crumbs.push(crumb);
 }
